    func application(_ application: UIApplication, didFailToRegisterForRemoteNotificationsWithError error: Error) {
        postNotificationRegistrationErrorToWeb(error.localizedDescription)
    }

    private func postNotificationTokenToWeb(_ token: String) {
        guard let controller = window?.rootViewController as? HybridWebViewController else { return }
        controller.perform(#selector(bridgePushToken(_:)), with: token)
    }

    private func postNotificationRegistrationErrorToWeb(_ message: String) {
        guard let controller = window?.rootViewController as? HybridWebViewController else { return }
        controller.perform(#selector(bridgePushError(_:)), with: message)
    }
